+fn write_u8_dec(buf: &mut [u8], n: u8) -> usize {
+    if n >= 100 {
+        let hundreds = n / 100;
+        let tens = (n / 10) % 10;
+        let ones = n % 10;
+        buf[0] = b'0' + hundreds;
+        buf[1] = b'0' + tens;
